import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import {
  AppBar,
  Toolbar,
  Typography,
  Button,
  IconButton,
  Menu,
  MenuItem,
  Box,
  Avatar,
  useTheme,
} from '@mui/material';
import {
  HomeIcon,
  UserCircleIcon,
  CogIcon,
  BellIcon,
  ChatBubbleLeftRightIcon,
  ArrowRightOnRectangleIcon,
} from '@heroicons/react/24/outline';
import { motion } from 'framer-motion';
import { useAuth } from '../contexts/AuthContext';
import AnimatedContainer from './AnimatedContainer';

const Navbar: React.FC = () => {
  const theme = useTheme();
  const navigate = useNavigate();
  const { user, logout } = useAuth();
  const [anchorEl, setAnchorEl] = useState<null | HTMLElement>(null);

  const handleMenu = (event: React.MouseEvent<HTMLElement>) => {
    setAnchorEl(event.currentTarget);
  };

  const handleClose = () => {
    setAnchorEl(null);
  };

  const handleLogout = () => {
    logout();
    handleClose();
    navigate('/login');
  };

  return (
    <AppBar
      position="static"
      elevation={0}
      sx={{
        backgroundColor: 'background.paper',
        borderBottom: `1px solid ${theme.palette.divider}`,
      }}
    >
      <Toolbar>
        <AnimatedContainer>
          <Box
            component={motion.div}
            whileHover={{ scale: 1.05 }}
            whileTap={{ scale: 0.95 }}
            sx={{ display: 'flex', alignItems: 'center', gap: 1 }}
          >
            <HomeIcon className="h-6 w-6" style={{ color: theme.palette.primary.main }} />
            <Typography
              variant="h6"
              component={Link}
              to="/"
              sx={{
                textDecoration: 'none',
                color: 'text.primary',
                fontWeight: 700,
                '&:hover': {
                  color: 'primary.main',
                },
              }}
            >
              HunterBot
            </Typography>
          </Box>
        </AnimatedContainer>

        <Box sx={{ flexGrow: 1 }} />

        {user ? (
          <AnimatedContainer>
            <Box sx={{ display: 'flex', alignItems: 'center', gap: 2 }}>
              <IconButton
                component={motion.button}
                whileHover={{ scale: 1.1 }}
                whileTap={{ scale: 0.9 }}
                onClick={() => navigate('/notifications')}
              >
                <BellIcon className="h-5 w-5" style={{ color: theme.palette.text.secondary }} />
              </IconButton>

              <IconButton
                component={motion.button}
                whileHover={{ scale: 1.1 }}
                whileTap={{ scale: 0.9 }}
                onClick={() => navigate('/messages')}
              >
                <ChatBubbleLeftRightIcon
                  className="h-5 w-5"
                  style={{ color: theme.palette.text.secondary }}
                />
              </IconButton>

              <IconButton
                component={motion.button}
                whileHover={{ scale: 1.1 }}
                whileTap={{ scale: 0.9 }}
                onClick={handleMenu}
              >
                <Avatar
                  sx={{
                    width: 32,
                    height: 32,
                    bgcolor: 'primary.main',
                  }}
                >
                  {user.name?.[0]?.toUpperCase() || 'U'}
                </Avatar>
              </IconButton>

              <Menu
                anchorEl={anchorEl}
                open={Boolean(anchorEl)}
                onClose={handleClose}
                PaperProps={{
                  elevation: 0,
                  sx: {
                    overflow: 'visible',
                    filter: 'drop-shadow(0px 2px 8px rgba(0,0,0,0.1))',
                    mt: 1.5,
                    '&:before': {
                      content: '""',
                      display: 'block',
                      position: 'absolute',
                      top: 0,
                      right: 14,
                      width: 10,
                      height: 10,
                      bgcolor: 'background.paper',
                      transform: 'translateY(-50%) rotate(45deg)',
                      zIndex: 0,
                    },
                  },
                }}
                transformOrigin={{ horizontal: 'right', vertical: 'top' }}
                anchorOrigin={{ horizontal: 'right', vertical: 'bottom' }}
              >
                <MenuItem
                  component={Link}
                  to="/profile"
                  onClick={handleClose}
                  sx={{ display: 'flex', alignItems: 'center', gap: 1 }}
                >
                  <UserCircleIcon className="h-5 w-5" style={{ color: theme.palette.text.secondary }} />
                  Profile
                </MenuItem>
                <MenuItem
                  component={Link}
                  to="/settings"
                  onClick={handleClose}
                  sx={{ display: 'flex', alignItems: 'center', gap: 1 }}
                >
                  <CogIcon className="h-5 w-5" style={{ color: theme.palette.text.secondary }} />
                  Settings
                </MenuItem>
                <MenuItem
                  onClick={handleLogout}
                  sx={{ display: 'flex', alignItems: 'center', gap: 1 }}
                >
                  <ArrowRightOnRectangleIcon
                    className="h-5 w-5"
                    style={{ color: theme.palette.text.secondary }}
                  />
                  Logout
                </MenuItem>
              </Menu>
            </Box>
          </AnimatedContainer>
        ) : (
          <AnimatedContainer>
            <Box sx={{ display: 'flex', gap: 2 }}>
              <Button
                component={motion.button}
                whileHover={{ scale: 1.05 }}
                whileTap={{ scale: 0.95 }}
                variant="outlined"
                onClick={() => navigate('/login')}
              >
                Login
              </Button>
              <Button
                component={motion.button}
                whileHover={{ scale: 1.05 }}
                whileTap={{ scale: 0.95 }}
                variant="contained"
                onClick={() => navigate('/register')}
              >
                Register
              </Button>
            </Box>
          </AnimatedContainer>
        )}
      </Toolbar>
    </AppBar>
  );
};

export default Navbar;
